local HttpService = game:GetService("HttpService")

local url = "https://www.bronzeforever.net/api/v3/game/status"
local response = request({
    Url = url,
    Method = "GET",
})

local pokemon_brick_bronze_placeId = 0
if response and response.StatusCode == 200 then
    local decoded = HttpService:JSONDecode(response.Body)
    if decoded and decoded.game and decoded.game.placeId then
        pokemon_brick_bronze_placeId = decoded.game.placeId
    end
end

if game.PlaceId ~= tonumber(pokemon_brick_bronze_placeId) then
    return
end

